Hi, in the case of node.js durable uses express to implement the REST API. You can reuse the express app as follows:

```javascript
var d = require('durable');
var m = d.m, s = d.s, c = d.c;
var timeout = d.timeout;

d.ruleset('test', {
    whenAll: [
        c.first = m.location.eq('US'),
        c.second = m.location.eq('CA')
    ],
    run: function(c) {
        console.log('test fraud detected ' + c.first.amount + ' ' + c.second.amount);
    }
},
function (host) {
    host.post('test', {id: 1, sid: 1, amount: 200, location: 'US'});
    host.post('test', {id: 2, sid: 1, amount: 200, location: 'CA'});
});

d.runAll(null, null, null, function(host, app) {
    app.get('/testhello', function (req, res) {
        res.send('Hello World!');
    });
    app.run();
});
```

Please note the path for the `get` function is /testhello, the path /test collides with the rule definition url.

